535: ProcessCopyOptions(ParseState *pstate,
536: 				   CopyFormatOptions *opts_out,
537: 				   bool is_from,
538: 				   List *options)
539: {
540: 	bool		format_specified = false;
541: 	bool		freeze_specified = false;
542: 	bool		header_specified = false;
543: 	bool		on_error_specified = false;
544: 	bool		log_verbosity_specified = false;
545: 	bool		reject_limit_specified = false;
546: 	ListCell   *option;
547: 
548: 	/* Support external use for option sanity checking */
549: 	if (opts_out == NULL)
550: 		opts_out = (CopyFormatOptions *) palloc0(sizeof(CopyFormatOptions));
551: 
552: 	opts_out->file_encoding = -1;
553: 
554: 	/* Extract options from the statement node tree */
555: 	foreach(option, options)
556: 	{
557: 		DefElem    *defel = lfirst_node(DefElem, option);
558: 
559: 		if (strcmp(defel->defname, "format") == 0)
560: 		{
561: 			char	   *fmt = defGetString(defel);
562: 
563: 			if (format_specified)
564: 				errorConflictingDefElem(defel, pstate);
565: 			format_specified = true;
566: 			if (strcmp(fmt, "text") == 0)
567: 				 /* default format */ ;
568: 			else if (strcmp(fmt, "csv") == 0)
569: 				opts_out->csv_mode = true;
570: 			else if (strcmp(fmt, "binary") == 0)
571: 				opts_out->binary = true;
572: 			else
573: 				ereport(ERROR,
574: 						(errcode(ERRCODE_INVALID_PARAMETER_VALUE),
575: 						 errmsg("COPY format \"%s\" not recognized", fmt),
576: 						 parser_errposition(pstate, defel->location)));
577: 		}
578: 		else if (strcmp(defel->defname, "freeze") == 0)
579: 		{
580: 			if (freeze_specified)
581: 				errorConflictingDefElem(defel, pstate);
582: 			freeze_specified = true;
583: 			opts_out->freeze = defGetBoolean(defel);
584: 		}
585: 		else if (strcmp(defel->defname, "delimiter") == 0)
586: 		{
587: 			if (opts_out->delim)
588: 				errorConflictingDefElem(defel, pstate);
589: 			opts_out->delim = defGetString(defel);
590: 		}
591: 		else if (strcmp(defel->defname, "null") == 0)
592: 		{
593: 			if (opts_out->null_print)
594: 				errorConflictingDefElem(defel, pstate);
595: 			opts_out->null_print = defGetString(defel);
596: 		}
597: 		else if (strcmp(defel->defname, "default") == 0)
598: 		{
599: 			if (opts_out->default_print)
600: 				errorConflictingDefElem(defel, pstate);
601: 			opts_out->default_print = defGetString(defel);
602: 		}
603: 		else if (strcmp(defel->defname, "header") == 0)
604: 		{
605: 			if (header_specified)
606: 				errorConflictingDefElem(defel, pstate);
607: 			header_specified = true;
608: 			opts_out->header_line = defGetCopyHeaderChoice(defel, is_from);
609: 		}
610: 		else if (strcmp(defel->defname, "quote") == 0)
611: 		{
612: 			if (opts_out->quote)
613: 				errorConflictingDefElem(defel, pstate);
614: 			opts_out->quote = defGetString(defel);
615: 		}
616: 		else if (strcmp(defel->defname, "escape") == 0)
617: 		{
618: 			if (opts_out->escape)
619: 				errorConflictingDefElem(defel, pstate);
620: 			opts_out->escape = defGetString(defel);
621: 		}
622: 		else if (strcmp(defel->defname, "force_quote") == 0)
623: 		{
624: 			if (opts_out->force_quote || opts_out->force_quote_all)
625: 				errorConflictingDefElem(defel, pstate);
626: 			if (defel->arg && IsA(defel->arg, A_Star))
